import { useEffect, useMemo, useState } from "react";

import { zodResolver } from "@hookform/resolvers/zod";
import { useMutation } from "@tanstack/react-query";
import { ChevronRight, Copy, Eye, EyeOff, ShieldCheck, Smartphone, Sparkles, UserCog } from "lucide-react";
import { useForm, useWatch } from "react-hook-form";
import { Link, useNavigate } from "react-router-dom";
import { toast } from "sonner";
import { z } from "zod";

import { AuthLayout } from "@/components/layout/AuthLayout";
import { Button } from "@/components/ui/Button";
import { Card } from "@/components/ui/Card";
import { authService } from "@/services/endpoints/auth";
import { usersService } from "@/services/endpoints/users";
import type { AuthState } from "@/store/auth-store";
import { useAuthStore } from "@/store/auth-store";
import { cn } from "@/utils/cn";

const DEMO_SHORTCUTS = [
  {
    id: "customer",
    title: "Демо-абонент",
    caption: "SMS-сценарий для входа в личный кабинет клиента",
    phone: "+79005553311",
    mode: "sms" as const,
  },
  {
    id: "operator",
    title: "Оператор",
    caption: "Заполняет номер сотрудника (пароль вводится вручную)",
    phone: "+79005550077",
    mode: "password" as const,
  },
  {
    id: "super-admin",
    title: "Super Admin",
    caption: "Заполняет номер суперадмина (пароль вводится вручную)",
    phone: "+79005550099",
    mode: "password" as const,
  },
];

const baseSchema = z.object({
  phone: z.string().trim().min(5, "Введите телефон"),
  password: z.string().optional(),
  smsCode: z.string().optional(),
  totpCode: z.string().optional(),
});

type LoginValues = z.infer<typeof baseSchema>;

function getErrorMessage(error: unknown) {
  if (
    error &&
    typeof error === "object" &&
    "response" in error &&
    error.response &&
    typeof error.response === "object" &&
    "data" in error.response &&
    error.response.data &&
    typeof error.response.data === "object" &&
    "detail" in error.response.data
  ) {
    return String(error.response.data.detail);
  }

  if (error instanceof Error) {
    return error.message;
  }

  return "Не удалось выполнить запрос. Попробуйте ещё раз.";
}

function LoginPage() {
  const navigate = useNavigate();
  const setSession = useAuthStore((state: AuthState) => state.setSession);
  const setUser = useAuthStore((state: AuthState) => state.setUser);
  const [mode, setMode] = useState<"sms" | "password">("sms");
  const [demoCode, setDemoCode] = useState<string | null>(null);
  const [requestedPhone, setRequestedPhone] = useState<string | null>(null);
  const [cooldown, setCooldown] = useState(0);
  const [twoFactorToken, setTwoFactorToken] = useState<string | null>(null);
  const [showPassword, setShowPassword] = useState(false);
  const [showTotpCode, setShowTotpCode] = useState(false);

  const form = useForm<LoginValues>({
    resolver: zodResolver(baseSchema),
    defaultValues: {
      phone: "",
      password: "",
      smsCode: "",
      totpCode: "",
    },
  });

  const phoneValue = useWatch({ control: form.control, name: "phone" }) ?? "";
  const phoneField = form.register("phone");
  const isTwoFactorStep = Boolean(twoFactorToken);
  const isSmsVerificationStep = mode === "sms" && Boolean(requestedPhone);
  const activeStep = isTwoFactorStep ? 3 : isSmsVerificationStep ? 2 : 1;

  const submitLabel = useMemo(() => {
    if (isTwoFactorStep) {
      return "Подтвердить 2FA";
    }

    if (mode === "password") {
      return "Войти по паролю";
    }

    return isSmsVerificationStep ? "Войти по коду" : "Получить SMS-код";
  }, [isSmsVerificationStep, isTwoFactorStep, mode]);

  useEffect(() => {
    if (!cooldown) {
      return;
    }

    const timer = window.setTimeout(() => setCooldown((current) => Math.max(current - 1, 0)), 1000);
    return () => window.clearTimeout(timer);
  }, [cooldown]);

  const completeAuth = async (result: Awaited<ReturnType<typeof authService.login>>, fallbackName: string) => {
    if (!result.access_token || !result.refresh_token || !result.expires_in) {
      toast.error("Сессия не была создана. Повторите попытку входа.");
      return;
    }

    setSession({
      accessToken: result.access_token,
      refreshToken: result.refresh_token,
      expiresIn: result.expires_in,
      role: result.role,
    });

    const profile = await usersService.me();
    setUser(profile);
    toast.success(`Добро пожаловать, ${profile.first_name || fallbackName}!`);
    navigate(result.role === "user" ? "/dashboard" : "/admin/dashboard", { replace: true });
  };

  const requestCodeMutation = useMutation({
    mutationFn: (phone: string) => authService.login({ phone }),
    onSuccess: async (result, phone) => {
      if (result.access_token) {
        await completeAuth(result, phone);
        return;
      }

      setRequestedPhone(phone);
      setDemoCode(result.demo_sms_code ?? null);
      setCooldown(result.demo_sms_ttl ? Math.min(result.demo_sms_ttl, 60) : 60);
      toast.success(result.message ?? "Код отправлен. Проверьте SMS.");
      form.setFocus("smsCode");
    },
    onError: (error) => {
      toast.error(getErrorMessage(error));
    },
  });

  const loginMutation = useMutation({
    mutationFn: async (values: LoginValues) => {
      if (twoFactorToken) {
        return authService.completeTwoFactorLogin(twoFactorToken, values.totpCode?.trim() || "");
      }

      return authService.login({
        phone: values.phone.trim(),
        password: mode === "password" ? values.password?.trim() : undefined,
        sms_code: mode === "sms" ? values.smsCode?.trim() : undefined,
      });
    },
    onSuccess: async (result, values) => {
      if (result.requires_2fa && result.two_factor_token) {
        setTwoFactorToken(result.two_factor_token);
        form.setValue("totpCode", "");
        form.setFocus("totpCode");
        toast.info("Введите код 2FA, чтобы завершить вход.");
        return;
      }

      await completeAuth(result, values.phone.trim());
    },
    onError: (error) => {
      toast.error(getErrorMessage(error));
    },
  });

  const handleModeChange = (nextMode: "sms" | "password") => {
    setMode(nextMode);
    setTwoFactorToken(null);
    setRequestedPhone(null);
    setDemoCode(null);
    setCooldown(0);
    form.clearErrors();
    form.setValue("smsCode", "");
    form.setValue("totpCode", "");
    if (nextMode === "sms") {
      form.setValue("password", "");
    }
  };

  const handleShortcut = (shortcut: (typeof DEMO_SHORTCUTS)[number]) => {
    handleModeChange(shortcut.mode);
    form.reset({
      phone: shortcut.phone,
      password: shortcut.mode === "password" ? "" : form.getValues("password"),
      smsCode: "",
      totpCode: "",
    });

    if (shortcut.mode === "sms") {
      requestCodeMutation.mutate(shortcut.phone);
      return;
    }

    toast.success(`Номер для роли ${shortcut.title} подставлен. Введите пароль вручную.`);
  };

  const handleCopyDemoCode = async () => {
    if (!demoCode) {
      return;
    }

    try {
      await navigator.clipboard.writeText(demoCode);
      form.setValue("smsCode", demoCode);
      toast.success("Демо-код скопирован и подставлен в форму.");
    } catch {
      form.setValue("smsCode", demoCode);
      toast.success("Демо-код подставлен в форму.");
    }
  };

  const onSubmit = form.handleSubmit((values) => {
    if (isTwoFactorStep) {
      if (!values.totpCode?.trim()) {
        form.setError("totpCode", { type: "manual", message: "Введите код из приложения-аутентификатора" });
        return;
      }

      loginMutation.mutate(values);
      return;
    }

    if (mode === "password") {
      if (!values.password?.trim()) {
        form.setError("password", { type: "manual", message: "Введите пароль" });
        return;
      }

      loginMutation.mutate(values);
      return;
    }

    if (!isSmsVerificationStep && !values.smsCode?.trim()) {
      requestCodeMutation.mutate(values.phone.trim());
      return;
    }

    if (!values.smsCode?.trim()) {
      form.setError("smsCode", { type: "manual", message: "Введите код из SMS" });
      return;
    }

    loginMutation.mutate(values);
  });

  return (
    <AuthLayout>
      <Card className="auth-form-card stack-lg">
        <div className="auth-form-head">
          <div>
            <p className="section-eyebrow">Sign In</p>
            <h2 className="auth-form-title">Вход в MTN SPA</h2>
            <p className="auth-form-copy">
              Один экран для абонента, оператора и административных сценариев: SMS-код,
              пароль и обязательный 2FA для сотрудников без переключения между разными интерфейсами.
            </p>
          </div>
          <div className="auth-head-badge">
            <Sparkles size={16} />
            <span>Premium auth flow</span>
          </div>
        </div>

        <div className="auth-stepper">
          {[
            { id: 1, title: "Идентификация", description: "Телефон и способ входа" },
            { id: 2, title: "Подтверждение", description: mode === "sms" ? "Код из SMS" : "Проверка пароля" },
            { id: 3, title: "Безопасность", description: "Дополнительный 2FA" },
          ].map((step) => (
            <div
              key={step.id}
              className={cn(
                "auth-step-card",
                activeStep === step.id && "is-active",
                activeStep > step.id && "is-complete",
              )}
            >
              <div className="auth-step-index">0{step.id}</div>
              <div>
                <strong>{step.title}</strong>
                <p>{step.description}</p>
              </div>
            </div>
          ))}
        </div>

        <div className="auth-mode-switch" role="tablist" aria-label="Режим авторизации">
          <Button
            variant={mode === "sms" ? "primary" : "secondary"}
            onClick={() => handleModeChange("sms")}
            type="button"
          >
            <Smartphone size={16} />
            Вход по SMS
          </Button>
          <Button
            variant={mode === "password" ? "primary" : "secondary"}
            onClick={() => handleModeChange("password")}
            type="button"
          >
            <ShieldCheck size={16} />
            Вход по паролю
          </Button>
        </div>

        <div className="auth-demo-grid">
          {DEMO_SHORTCUTS.map((shortcut) => (
            <button
              key={shortcut.id}
              type="button"
              className="auth-demo-card"
              onClick={() => handleShortcut(shortcut)}
            >
              <div className="auth-demo-card-copy">
                <strong>{shortcut.title}</strong>
                <p>{shortcut.caption}</p>
                <span>{shortcut.phone}</span>
              </div>
              <ChevronRight size={18} />
            </button>
          ))}
        </div>

        <form className="stack-md" onSubmit={onSubmit}>
          <div className="field">
            <label htmlFor="phone">Телефон</label>
            <input
              id="phone"
              placeholder="+7 (999) 123-45-67"
              autoComplete="tel"
              {...phoneField}
              onChange={(event) => {
                phoneField.onChange(event);

                if (!requestedPhone || event.target.value.trim() === requestedPhone.trim()) {
                  return;
                }

                setRequestedPhone(null);
                setDemoCode(null);
                setCooldown(0);
                form.setValue("smsCode", "");
              }}
            />
            <span className="muted">
              {form.formState.errors.phone?.message ?? "Используйте номер, привязанный к договору или staff-аккаунту."}
            </span>
          </div>

          {mode === "password" ? (
            <div className="field">
              <label htmlFor="password">Пароль</label>
              <div className="input-with-action">
                <input
                  id="password"
                  type={showPassword ? "text" : "password"}
                  placeholder="Введите пароль"
                  autoComplete="current-password"
                  {...form.register("password")}
                />
                <button
                  type="button"
                  className="input-action"
                  onClick={() => setShowPassword((current) => !current)}
                  aria-label={showPassword ? "Скрыть пароль" : "Показать пароль"}
                >
                  {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
                </button>
              </div>
              <span className="muted">
                {form.formState.errors.password?.message ??
                  "Парольный вход нужен для operator, admin и пользователей с настроенным паролем."}
              </span>
            </div>
          ) : (
            <div className="field">
              <label htmlFor="smsCode">SMS-код</label>
              <input
                id="smsCode"
                placeholder={isSmsVerificationStep ? "Введите код из SMS" : "Код появится после отправки"}
                inputMode="numeric"
                autoComplete="one-time-code"
                {...form.register("smsCode")}
              />
              <span className="muted">
                {form.formState.errors.smsCode?.message ??
                  (demoCode
                    ? `Демо-код готов: ${demoCode}`
                    : cooldown
                      ? `Повторная отправка будет доступна через ${cooldown} сек.`
                      : "Сначала запросите SMS-код, затем подтвердите вход.")}
              </span>
            </div>
          )}

          {mode === "sms" && isSmsVerificationStep ? (
            <Card className="auth-inline-card stack-sm">
              <div className="toolbar-row">
                <div>
                  <strong>Подтверждение номера</strong>
                  <p className="muted">Код отправлен на {requestedPhone}</p>
                </div>
                {demoCode ? (
                  <Button type="button" size="sm" variant="secondary" onClick={handleCopyDemoCode}>
                    <Copy size={14} />
                    Скопировать код
                  </Button>
                ) : null}
              </div>
              <div className="inline-actions">
                <Button
                  type="button"
                  variant="secondary"
                  size="sm"
                  disabled={cooldown > 0 || requestCodeMutation.isPending}
                  onClick={() => requestCodeMutation.mutate(phoneValue.trim())}
                >
                  {requestCodeMutation.isPending ? "Отправляем..." : "Отправить код повторно"}
                </Button>
                <span className="muted">
                  {cooldown > 0 ? `Ожидайте ${cooldown} сек.` : "Можно запросить новый код"}
                </span>
              </div>
            </Card>
          ) : null}

          {isTwoFactorStep ? (
            <Card className="auth-inline-card stack-sm">
              <div className="inline-actions">
                <ShieldCheck size={18} />
                <strong>Двухфакторная проверка</strong>
              </div>
              <p className="muted">
                Аккаунт сотрудника успешно прошёл парольный этап. Теперь подтвердите вход одноразовым
                кодом из приложения-аутентификатора.
              </p>
              <div className="field">
                <label htmlFor="totpCode">Код 2FA</label>
                <div className="input-with-action">
                  <input
                    id="totpCode"
                    type={showTotpCode ? "text" : "password"}
                    inputMode="numeric"
                    placeholder="6 цифр"
                    {...form.register("totpCode")}
                  />
                  <button
                    type="button"
                    className="input-action"
                    onClick={() => setShowTotpCode((current) => !current)}
                    aria-label={showTotpCode ? "Скрыть код" : "Показать код"}
                  >
                    {showTotpCode ? <EyeOff size={16} /> : <Eye size={16} />}
                  </button>
                </div>
                <span className="muted">
                  {form.formState.errors.totpCode?.message ?? "Код проверяется перед входом в административную панель."}
                </span>
              </div>
            </Card>
          ) : null}

          <Button disabled={loginMutation.isPending || requestCodeMutation.isPending} type="submit">
            {loginMutation.isPending || requestCodeMutation.isPending ? "Обрабатываем..." : submitLabel}
          </Button>
        </form>

        <div className="auth-links-grid">
          <Link className="link-line" to="/recover">
            Восстановить доступ
          </Link>
          <Link className="link-line" to="/register">
            Новый пользователь? Зарегистрироваться
          </Link>
        </div>

        <Card className="auth-inline-card stack-sm">
          <div className="inline-actions">
            <UserCog size={18} />
            <strong>Staff flow без отдельной формы</strong>
          </div>
          <p className="muted">
            Operator и admin используют тот же экран: парольный вход, затем 2FA и мгновенный
            переход в административную зону без дополнительного редиректа на старую страницу.
          </p>
        </Card>
      </Card>
    </AuthLayout>
  );
}

export default LoginPage;
